    }
}

import java.util.*;
import java.util.stream.*;

public class StreamDemo {
    public static void main(String[] args) {
        List<Integer> numbers = Arrays.asList(5, 3, 8, 1, 9, 2, 7, 4, 6, 10);

        // Filter evens, square them, sort, collect
        List<Integer> result = numbers.stream()
            .filter(n -> n % 2 == 0)      // [8, 2, 4, 6, 10]
            .map(n -> n * n)              // [64, 4, 16, 36, 100]
            .sorted()                     // [4, 16, 36, 64, 100]
            .collect(Collectors.toList());
        System.out.println("Result: " + result);

        // Statistics
        IntSummaryStatistics stats = numbers.stream()
            .mapToInt(Integer::intValue)
            .summaryStatistics();
        System.out.println("Count: " + stats.getCount());
        System.out.println("Sum: " + stats.getSum());
        System.out.println("Average: " + stats.getAverage());
        System.out.println("Max: " + stats.getMax());
        System.out.println("Min: " + stats.getMin());

        // String operations
        List<String> names = Arrays.asList("Alice", "Bob", "Charlie", "Anna", "Dave");
        String nameString = names.stream()
            .filter(n -> n.startsWith("A"))
            .map(String::toUpperCase)
            .sorted()
            .collect(Collectors.joining(", "));
        System.out.println("Names starting with A: " + nameString);
    }
}

lessons.explanation:
Now it is time to put everything you have learned together and build a complete command-line application. A CLI (Command-Line Interface) application runs in the terminal and interacts with users through text input and output. This is an excellent way to practice Java before moving to GUI or web applications.

Planning the Application
We will build a Student Grade Manager CLI application that allows users to:
1. Add a student with their name
2. Add grades for a student
3. View all students and their averages
4. Find the top student
5. Exit the application

This uses: classes, objects, collections (HashMap, ArrayList), loops, conditionals, methods, exception handling, and user input.

Reading User Input with Scanner
Import java.util.Scanner:
Scanner scanner = new Scanner(System.in);
String input = scanner.nextLine(); // reads a whole line
int num = scanner.nextInt(); // reads an integer
double d = scanner.nextDouble(); // reads a double
Always call scanner.close() when done, or use try-with-resources.

Application Architecture
Good CLI applications separate concerns:
- Model class: holds data (Student class)
- Service class: business logic (GradeBook class)
- Main/UI class: handles user interaction (input/output)

Building the Menu Loop
A CLI app typically has a main loop that displays a menu, reads a choice, and executes the corresponding action:
while (true) {
    printMenu();
    int choice = scanner.nextInt();
    scanner.nextLine(); // consume newline
    switch (choice) {
        case 1: addStudent(); break;
        case 2: addGrade(); break;
        case 3: viewAll(); break;
        case 4: findTop(); break;
        case 5: System.out.println("Goodbye!"); return;
        default: System.out.println("Invalid option.");
    }
}

Input Validation
Always validate user input. Wrap Scanner reads in try-catch for NumberFormatException. Check for empty strings. Provide helpful error messages and let the user try again.

Formatted Output
Use printf or String.format for clean, aligned output:
System.out.printf("%-15s %6.2f%n", name, average);
%-15s: left-align string in 15-char field
%6.2f: float with 6 total width, 2 decimal places

This lesson walks through the complete application, demonstrating how all previous lessons come together in a real project.

examples.code:
import java.util.*;

public class GradeManager {
    private HashMap<String, ArrayList<Integer>> gradeBook = new HashMap<>();
    private Scanner scanner = new Scanner(System.in);

    public void run() {
        System.out.println("=== Student Grade Manager ===");
        while (true) {
            printMenu();
            String choice = scanner.nextLine().trim();
            switch (choice) {
                case "1": addStudent(); break;
                case "2": addGrade(); break;
                case "3": viewAll(); break;
                case "4": findTopStudent(); break;
                case "5":
                    System.out.println("Goodbye!");
                    scanner.close();
                    return;
                default:
                    System.out.println("Invalid option. Try again.");
            }
        }
    }

    private void printMenu() {
        System.out.println("\n1. Add Student\n2. Add Grade\n3. View All\n4. Top Student\n5. Exit");
        System.out.print("Choice: ");
    }

    private void addStudent() {
        System.out.print("Enter student name: ");
        String name = scanner.nextLine().trim();
        if (name.isEmpty()) {
            System.out.println("Name cannot be empty.");
            return;
        }
        gradeBook.putIfAbsent(name, new ArrayList<>());
        System.out.println(name + " added.");
    }

    private void addGrade() {
        System.out.print("Student name: ");
        String name = scanner.nextLine().trim();
        if (!gradeBook.containsKey(name)) {
            System.out.println("Student not found.");
            return;
        }
        System.out.print("Enter grade (0-100): ");
        try {
            int grade = Integer.parseInt(scanner.nextLine().trim());
            if (grade < 0 || grade > 100) throw new IllegalArgumentException();
            gradeBook.get(name).add(grade);
            System.out.println("Grade added.");
        } catch (Exception e) {
            System.out.println("Invalid grade. Enter a number between 0 and 100.");
        }
    }

    private void viewAll() {
        if (gradeBook.isEmpty()) {
            System.out.println("No students yet.");
            return;
        }
        System.out.printf("%n%-20s %-10s %-10s%n", "Name", "Grades", "Average");
        System.out.println("-".repeat(42));
        for (Map.Entry<String, ArrayList<Integer>> entry : gradeBook.entrySet()) {
            double avg = entry.getValue().stream()
                .mapToInt(Integer::intValue).average().orElse(0);
            System.out.printf("%-20s %-10s %-10.2f%n",
                entry.getKey(), entry.getValue(), avg);
        }
    }

    private void findTopStudent() {
        gradeBook.entrySet().stream()
            .filter(e -> !e.getValue().isEmpty())
            .max(Comparator.comparingDouble(e ->
                e.getValue().stream().mapToInt(Integer::intValue).average().orElse(0)))
            .ifPresentOrElse(
                e -> System.out.println("Top student: " + e.getKey()),
                () -> System.out.println("No grades recorded yet.")
            );
    }

    public static void main(String[] args) {
        new GradeManager().run();
    }
}

// Transaction.java (abstract base)
public abstract class Transaction {
    private static int nextId = 1;
    private int id;
    private double amount;
    private String description;
    private String date;

    public Transaction(double amount, String description, String date) {
        this.id = nextId++;
        this.amount = amount;
        this.description = description;
        this.date = date;
    }

    public int getId() { return id; }
    public double getAmount() { return amount; }
    public String getDescription() { return description; }
    public String getDate() { return date; }

    public abstract String getType();

    @Override
    public String toString() {
        return String.format("[%d] %s | $%.2f | %s | %s",
            id, getType(), amount, description, date);
    }
}

// Income.java
public class Income extends Transaction {
    public Income(double amount, String description, String date) {
        super(amount, description, date);
    }
    @Override
    public String getType() { return "INCOME"; }
}

// Expense.java
public class Expense extends Transaction {
    private String category;

    public Expense(double amount, String description, String date, String category) {
        super(amount, description, date);
        this.category = category;
    }

    public String getCategory() { return category; }

    @Override
    public String getType() { return "EXPENSE"; }

    @Override
    public String toString() {
        return super.toString() + " | Category: " + category;
    }
}

import java.util.*;
import java.util.stream.*;

public class BudgetTracker {
    private ArrayList<Transaction> transactions = new ArrayList<>();

    public void addTransaction(Transaction t) {
        transactions.add(t);
    }

    public double getTotalIncome() {
        return transactions.stream()
            .filter(t -> t instanceof Income)
            .mapToDouble(Transaction::getAmount)
            .sum();
    }

    public double getTotalExpenses() {
        return transactions.stream()
            .filter(t -> t instanceof Expense)
            .mapToDouble(Transaction::getAmount)
            .sum();
    }

    public double getBalance() {
        return getTotalIncome() - getTotalExpenses();
    }

    public Map<String, Double> getExpensesByCategory() {
        return transactions.stream()
            .filter(t -> t instanceof Expense)
            .map(t -> (Expense) t)
            .collect(Collectors.groupingBy(
                Expense::getCategory,
                Collectors.summingDouble(Expense::getAmount)
            ));
    }

    public void printAll() {
        if (transactions.isEmpty()) {
            System.out.println("No transactions.");
            return;
        }
        transactions.forEach(System.out::println);
        System.out.printf("%nIncome: $%.2f | Expenses: $%.2f | Balance: $%.2f%n",
            getTotalIncome(), getTotalExpenses(), getBalance());
    }

    public ArrayList<Transaction> getTransactions() {
        return transactions;
    }
}
